import moment from "moment";
export function currentTime() {
  var date = new Date();
  var y: any = date.getFullYear();
  var m: any =
    date.getMonth() + 1 < 10
      ? "0" + (date.getMonth() + 1)
      : date.getMonth() + 1;
  var d: any = date.getDate() < 10 ? "0" + date.getDate() : date.getDate();

  return moment(y + "" + m + "" + d, "YYYYMMDD")
}