
import { defineComponent, inject, ref } from "vue";
import { passorno } from "@/server/http/api/Amultitasking";
import { init } from "@/views/admin/hooks/user_init";
export default defineComponent({
  props: ["detail"],
  setup(props) {
    const visible = ref<boolean>(false);
    const visible1 = ref<boolean>(false);
    const desc = ref("");
    const init: any = inject("initgetTaskDetailInfo");
    const showModal = () => {
      visible.value = true;
    };

    const handleOk = (e: MouseEvent) => {
      passorno({
        itemId: props.detail.itemId,
        state: 3,
      }).then((res: any) => {
        if (res.data.code === 200) {
          init();
          visible.value = false;
          visible1.value = false;
          desc.value = "";
        }
      });
      visible.value = false;
    };
    const showModal1 = () => {
      visible1.value = true;
    };

    const handleOk1 = (e: MouseEvent) => {
      passorno({
        itemId: props.detail.itemId,
        state: 4,
        opinion: desc.value,
      }).then((res: any) => {
        if (res.data.code === 200) {
          init();
          visible.value = false;
          visible1.value = false;
          desc.value = "";
        }
      });
    };
    return {
      visible,
      visible1,
      desc,
      showModal,
      handleOk,
      showModal1,
      handleOk1,
    };
  },
});
