
import {
  computed,
  defineComponent,
  inject,
  onMounted,
  reactive,
  ref,
  toRaw,
  toRefs,
  watch,
} from "vue";
import { DownOutlined, SyncOutlined } from "@ant-design/icons-vue";
import ReturnTitle from "@/components/OS_component/ReturnTitle.vue";
import Graborders from "@/components/Amultitasking/modal/Graborders.vue";
import Information from "@/components/Amultitasking/modal/Information.vue";
import Instrument from "@/components/Amultitasking/modal/Instrument.vue";
import CheckItemState from "@/components/Amultitasking/CheckItemState.vue";
import ToReview from "@/components/Amultitasking/modal/ToReview.vue";
import UploadFile from "./UploadFile.vue";
import {
  start_test,
  end_test,
  passorno,
} from "@/server/http/api/Amultitasking";
import { notification } from "ant-design-vue";
import { getTime } from "@/utils/setData";
import { currentTime } from "@/utils/currentTime";
import { message } from "ant-design-vue";
import { useRoute } from "vue-router";
import { DownLoadOriginalrecord } from "@/utils/DownLoad";
const columns = [
  {
    dataIndex: "checkItemName",
    key: "checkItemName",
    title: "检测项",
  },
  {
    title: "检测方法",
    dataIndex: "methodName",
    key: "methodName",
  },
  {
    title: "检测依据",
    key: "standardName",
    dataIndex: "standardName",
  },
  {
    title: "状态",
    dataIndex: "state",
    slots: { customRender: "state" },
  },
  {
    title: "检测样次",
    key: "times",
    dataIndex: "times",
  },
  {
    title: "知识信息",
    key: "action",
    slots: { customRender: "action" },
  },
  {
    title: "操作",
    key: "info",
    slots: { customRender: "info" },
  },
  {
    title: "原始记录上传",
    key: "upload",
    slots: { customRender: "upload" },
  },
];
export default defineComponent({
  components: {
    ReturnTitle,
    Graborders,
    Information,
    Instrument,
    CheckItemState,
    UploadFile,
    ToReview,
    SyncOutlined,
    DownOutlined,
  },

  props: ["checkItemInfoList", "taskId", "sampleId"],
  setup(props, ctx) {
    let init: any = inject("initgetTaskDetailInfo");

    const state = reactive({
      selectedRowKeys: [],
      loading: false,
    });
    function downloadOriginalrecord(detail: any) {
      console.info("下载原始记录");
      let { taskId, sampleId } = props;
      DownLoadOriginalrecord({
        taskId,
        sampleId,
        checkItemId: detail.checkItemId,
      });
    }
    // 控制开始检测
    const hasSelected = ref(false);
    watch(
      () => state.selectedRowKeys,
      (newVal, o) => {
        let arr: any = [];
        newVal.forEach((item: any) => {
          arr.push(
            props.checkItemInfoList.find((val: any) => {
              return val.itemId === item;
            })
          );
        });

        if (arr.length === 0) {
          hasSelected.value = false;
        } else {
          hasSelected.value = arr.every((value: any) => {
            return value.state === 0;
          });
        }
      }
    );
    // 控制检测完成
    const checkSuc = ref(false);
    watch(
      () => state.selectedRowKeys,
      (newVal, o) => {
        let arr: any = [];
        newVal.forEach((item: any) => {
          arr.push(
            props.checkItemInfoList.find((val: any) => {
              return val.itemId === item;
            })
          );
        });

        if (arr.length === 0) {
          checkSuc.value = false;
        } else {
          checkSuc.value = arr.every((value: any) => {
            return value.state === 1;
          });
        }
      }
    );

    // 选择仪器信息
    let Instrument: any = [];
    Instrument = props.checkItemInfoList;
    // 待发送数据
    let InstrumentFormState: any = reactive({
      startTime: null,
      taskId: props.taskId,
      itemInstrumentEntityList: [],
    });
    onMounted(() => {
      InstrumentFormState.startTime = currentTime();
    });

    const start = () => {
      state.loading = true;

      // 检查仪器是否选择
      // InstrumentFormState.itemInstrumentEntityList.map((item: any) => {
      //   if (!item.ids) {
      //     console.warn("仪器未选择");
      //     let obj = Instrument.find((val: any) => {
      //       return item.itemId === val.itemId;
      //     });
      //     notification.warning({
      //       message: `${obj.checkItemName}仪器未选择`,
      //       description: "请先选择仪器",
      //       onClick: () => {},
      //     });
      //     return;
      //   }
      // });
      // let flag = InstrumentFormState.itemInstrumentEntityList.some(
      //   (item: any) => {
      //     return item.ids === undefined;
      //   }
      // );
      //
      // if (!flag) {
      let obj = toRaw(InstrumentFormState);
      obj.startTime = getTime(obj.startTime);
      start_test(obj).then((res: any) => {
        if (res.data.code === 200) {
          init();
          message.success("试验开始");
          state.loading = false;
          state.selectedRowKeys = [];
          InstrumentFormState.startTime = null;
        }
      });
      // } else {
      // state.loading = false;
      // }
    };
    // 选择检测项
    const onSelectChange = (selectedRowKeys: []) => {
      state.selectedRowKeys = selectedRowKeys;
      InstrumentFormState.itemInstrumentEntityList = [];
      selectedRowKeys.map((item: any) => {
        let obj: any = Instrument.find((val: any) => {
          return val.itemId === item;
        });
        if (InstrumentFormState.itemInstrumentEntityList.length > 0) {
          let index = InstrumentFormState.itemInstrumentEntityList.findIndex(
            (val: any) => {
              return val.itemId === obj.itemId;
            }
          );
          // 判断带提交数据是否有该itemId
          if (index === -1) {
            InstrumentFormState.itemInstrumentEntityList.push({
              itemId: obj.itemId,
              ids: toRaw(obj.ids),
            });
          }
        } else {
          InstrumentFormState.itemInstrumentEntityList.push({
            itemId: obj.itemId,
            ids: toRaw(obj.ids),
          });
        }

        // //console.log("list", InstrumentFormState);
      });
    };
    // 选择仪器
    function selectInstrument({ selectedRowKeys, itemId }: any) {
      Instrument.map((item: any) => {
        if (itemId === item.itemId) {
          Object.assign(item, { ids: selectedRowKeys });
          if (InstrumentFormState.itemInstrumentEntityList.length > 0) {
            let index = InstrumentFormState.itemInstrumentEntityList.findIndex(
              (val: any) => {
                return val.itemId === itemId;
              }
            );
            // 判断带提交数据是否有该itemId
            if (index === -1) {
              // 没有添加
              InstrumentFormState.itemInstrumentEntityList.push({
                itemId: itemId,
                ids: selectedRowKeys,
              });
            } else {
              // 有更新
              // //console.log("update", selectedRowKeys);

              Object.assign(
                InstrumentFormState.itemInstrumentEntityList[index],
                { ids: selectedRowKeys }
              );
            }
          } else {
            InstrumentFormState.itemInstrumentEntityList.push({
              itemId: itemId,
              ids: selectedRowKeys,
            });
          }
        }
      });
    }

    // 实验结束
    let result = ref();
    function endtest() {
      let timer = null;
      if (InstrumentFormState.startTime) {
        timer = InstrumentFormState.startTime;
      }
      let form: any = {
        itemInstrumentEntityList: [],
        endTime: getTime(timer),
        taskId: props.taskId,
        result: result.value,
      };
      InstrumentFormState.itemInstrumentEntityList.map((item: any) => {
        form.itemInstrumentEntityList.push(item.itemId);
      });
      end_test(form).then((res: any) => {
        //console.log(res);
        if (res.data.code === 200) {
          init();
          state.selectedRowKeys = [];
          InstrumentFormState.startTime = null;
        }
      });
    }

    // 撤回
    function chehui(id: number) {
      passorno({
        itemId: id,
        state: 1,
      }).then((res: any) => {
        if (res.data.code === 200) {
          init();
        }
      });
    }
    return {
      columns,
      result,
      chehui,
      downloadOriginalrecord,
      ...toRefs(state),
      ...toRefs(InstrumentFormState),
      start,
      hasSelected,
      checkSuc,
      onSelectChange,
      selectInstrument,
      endtest,
    };
  },
});
