
import { UploadOutlined } from "@ant-design/icons-vue";
import { message } from "ant-design-vue";
import { defineComponent, inject, ref } from "vue";
import { uploadOriginalRecord } from "@/server/http/api/Amultitasking";
interface FileItem {
  uid: string;
  name?: string;
  status?: string;
  response?: string;
  url?: string;
  preview?: string;
  originFileObj?: any;
  file: string | Blob;
}

export default defineComponent({
  components: {
    UploadOutlined,
  },

  props: ["type", "taskId", "sampleId", "checkItemId"],
  setup(props) {
    const fileList = ref<any[]>([]);
    const handleRemove = (file: any) => {
      const index = fileList.value.indexOf(file);
      const newFileList = fileList.value.slice();
      newFileList.splice(index, 1);
      fileList.value = newFileList;
    };

    const beforeUpload = (file: any) => {
      fileList.value = [...fileList.value, file];
      load();
      return false;
    };
    let init: any = inject("initgetTaskDetailInfo");

    function load() {
      let form: any = {
        taskId: props.taskId,
        sampleId: props.sampleId,
        checkItemId: props.checkItemId,
      };
      let Files = new FormData();
      Files.append("json", JSON.stringify(form));
      fileList.value.map((item: any) => {
        Files.append("file", item);
      });
      uploadOriginalRecord(Files).then((res: any) => {
        //console.log(res);
        if (res.data.code === 200) {
          init();
        }
      });
    }

    return {
      fileList,
      handleRemove,
      beforeUpload,
      load,
    };
  },
});
