
import { computed, defineComponent, provide, reactive, ref, toRefs } from "vue";

import ReturnTitle from "@/components/OS_component/ReturnTitle.vue";
import Graborders from "@/components/Amultitasking/modal/Graborders.vue";
import SelectCheckItem from "@/components/Amultitasking/StartTest/SelectCheckItem.vue";
import {
  getTaskDetailInfo,
  getTeamUserName,
} from "../../../../../server/http/api/Amultitasking";

import { DownLoadEntrust } from "@/utils/DownLoad";
import { useRoute } from "vue-router";
const columns = [
  {
    dataIndex: "checkItemName",
    key: "checkItemName",
    title: "检测项",
  },
  {
    title: "检测方法",
    dataIndex: "methodName",
    key: "methodName",
  },
  {
    title: "检测依据",
    key: "standardName",
    dataIndex: "standardName",
  },

  // {
  //   title: "单价",
  //   key: "checkPrice",
  //   dataIndex: "checkPrice",
  // },
  {
    title: "检测样次",
    key: "times",
    dataIndex: "times",
  },
  {
    title: "知识信息",
    key: "action",
    slots: { customRender: "action" },
  },
  {
    title: "操作",
    key: "info",
    slots: { customRender: "info" },
  },
];
export default defineComponent({
  components: { ReturnTitle, Graborders, SelectCheckItem },
  name: "TaskacceptanceDetail",

  setup() {
    const route: any = useRoute();
    const team = ref();
    // 任务单详情
    const data = reactive({
      sampleDetailList: [],
      taskId: "",
      taskCode: "",
      orderer: "",
      orderTime: "",
      requiredCompletionTime: "",
      cost: "",
      samplingMethod: "",
      checkPurpose: "",
      presentInformation: "",
      fileUrl: "",
      array: "",
    });
    getTaskDetailInfo(route.params.id * 1).then((res: any) => {
      if (res.data.code === 200) {
        Object.assign(data, res.data.data);
        //console.log(data);
      }
    });

    function initgetTaskDetailInfo() {
      getTaskDetailInfo(route.params.id * 1).then((res: any) => {
        if (res.data.code === 200) {
          Object.assign(data, res.data.data);
          //console.log(data);
        }
      });
    }
    provide("initgetTaskDetailInfo", initgetTaskDetailInfo);

    function download(taskId: number) {
      DownLoadEntrust(taskId);
    }

    return {
      columns,
      team,
      data,
      download,
      ...toRefs(data),
      initgetTaskDetailInfo,
    };
  },
});
