
import { defineComponent, reactive, ref, toRefs } from "vue";
import { InstrumentList } from "@/server/http/api/Amultitasking";
const columns = [
  {
    title: "仪器名称",
    dataIndex: "name",
  },
  {
    title: "编号",
    dataIndex: "code",
  },
  {
    title: "型号",
    dataIndex: "model",
  },
];
export default defineComponent({
  props: ["detail"],
  emits: ["selectInstrument"],
  setup(props, ctx) {
    const visible = ref<boolean>(false);
    const Instrumentlist = ref([]);
    const showModal = (detail: any) => {
      InstrumentList(detail.checkItemId).then((res: any) => {
        if (res.data.code === 200) {
          Instrumentlist.value = res.data.data;
        }
      });
      visible.value = true;
    };

    const handleOk = (e: MouseEvent) => {
   
      visible.value = false;
    };

    const state = reactive({
      selectedRowKeys: [], // Check here to configure the default column
      loading: false,
    });
    const showName: any = ref([]);
    const onSelectChange = (selectedRowKeys: []) => {
      state.selectedRowKeys = selectedRowKeys;
      showName.value = [];
      selectedRowKeys.map((item: any) => {
        let obj: any = Instrumentlist.value.find((val: any) => {
          return val.id === item;
        });
        showName.value = [...showName.value, obj.name];
      });

      ctx.emit("selectInstrument", {
        itemId: props.detail.itemId,
        selectedRowKeys,
      });
    };
    return {
      visible,
      showModal,
      handleOk,
      onSelectChange,
      Instrumentlist,
      columns,
      ...toRefs(state),
      showName,
    };
  },
});
